+}
+
+#[test]
+fn report_serde_roundtrip_populated() {
+    let mut engine = ExtractionEngine::new(ExtractionConfig::relaxed());
+    engine.add_input(ReproInput::new(
+        "i1".into(),
+        FailureCategory::RenderCrash,
+        200,
+        5,
+        3,
+    ));
+    engine.add_repro(MinimizedRepro::new(
+        "i1".into(),
