+        recommended_action: "fix".into(),
+    });
+    let report = engine.evaluate(epoch());
+    let json = serde_json::to_string(&report).unwrap();
+    let back: ExtractionReport = serde_json::from_str(&json).unwrap();
+    assert_eq!(report, back);
+}
